CREATE TABLE IF NOT EXISTS accessory_units (
  id INT AUTO_INCREMENT PRIMARY KEY,
  accessoryId INT NOT NULL,
  serialNumber VARCHAR(50),
  status ENUM('disponivel','alugado','perdido','manutencao','roubado') NOT NULL DEFAULT 'disponivel',
  observacao TEXT,
  createdAt TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
ALTER TABLE bike_maintenance_logs ADD COLUMN IF NOT EXISTS tamanhoBikeId INT NULL;
ALTER TABLE bike_maintenance_logs ADD COLUMN IF NOT EXISTS quantidadeAfetada INT NOT NULL DEFAULT 1;

